#include <iostream>
#include <type_traits>

template <typename T>
void printValue(T value) {
    if constexpr (std::is_same_v<T, char>) {
        std::cout << "Value (ASCII): " << static_cast<int>(value) << std::endl;
    } else {
        std::cout << "Value: " << value << std::endl;
    }
}

int main() {
    printValue(10);
    printValue('A');
    return 0;
}
